import json
import requests
from urllib.parse import urlparse

ALLOWED_DOMAINS = ['example.com', 'api.example.com']

def is_safe_url(url):
    parsed_url = urlparse(url)
    return parsed_url.scheme in ['http', 'https'] and parsed_url.netloc in ALLOWED_DOMAINS

